import numpy as np

def algo(initial_population, individual_upper, individual_lower, objective_function):
    max_evaluations = 30000
    evaluations = 0
    num_solutions = initial_population.shape[0]
    dimensions = initial_population.shape[1]
    best_solution = initial_population[np.argmin([objective_function(ind) for ind in initial_population])]

    while evaluations < max_evaluations:
        for i in range(num_solutions):
            if evaluations >= max_evaluations:
                break
            step_size = np.random.uniform(-1, 1, dimensions)
            new_solution = initial_population[i] + step_size * (best_solution - initial_population[i])
            new_solution = np.clip(new_solution, individual_lower, individual_upper)
            new_value = objective_function(new_solution)
            evaluations += 1

            if new_value < objective_function(initial_population[i]):
                initial_population[i] = new_solution
                if new_value < objective_function(best_solution):
                    best_solution = new_solution

        local_search_candidates = np.random.choice(num_solutions, size=num_solutions//5, replace=False)
        for candidate in local_search_candidates:
            if evaluations >= max_evaluations:
                break
            local_step = np.random.uniform(-0.1, 0.1, dimensions)
            local_solution = initial_population[candidate] + local_step
            local_solution = np.clip(local_solution, individual_lower, individual_upper)
            if objective_function(local_solution) < objective_function(initial_population[candidate]):
                initial_population[candidate] = local_solution
                if objective_function(local_solution) < objective_function(best_solution):
                    best_solution = local_solution

    return best_solution
